import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import response from './response.json';

interface OrderData {
  orderId: string;
  status: string;
  deliveryProgress: number;
  estimatedArrival: string;
}

interface DeliveryTimeline {
  time: string;
  status: string;
}

interface WidgetData {
  order: OrderData;
  deliveryTimeline: DeliveryTimeline[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { order, deliveryTimeline } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Order Status
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Order ID: {order.orderId}
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Status: {order.status}
            </Typography>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Estimated Arrival: {order.estimatedArrival}
            </Typography>
          </Box>

          <Box sx={{ display: 'flex', alignItems: 'center', mt: 2 }}>
            <CircularProgress variant="determinate" value={order.deliveryProgress} sx={{ color: '#FFC107', mr: 2 }} />
            <Typography variant="body2" sx={{ color: '#FF5722' }}>
              {order.deliveryProgress}%
            </Typography>
          </Box>

          <Stack spacing={1}>
            <Typography variant="body2" fontWeight={500} sx={{ mt: 1 }}>
              Delivery Timeline
            </Typography>
            {deliveryTimeline.map((item, index) => (
              <Box key={index}>
                <Typography variant="caption" color="text.secondary">
                  {item.time} - {item.status}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
